const signal = $('Get Approved Signal').first().json;
const portfolio = $input.first().json;

if (!portfolio.system_active) {
  throw new Error('System is stopped — cannot execute trade');
}

const available = parseFloat(portfolio.available_capital);
const size = parseFloat(signal.position_size_usdt);

if (size > available) {
  throw new Error(`Insufficient capital: need $${size}, have $${available}`);
}

// Build Binance order params
const symbol = signal.coin.replace('/', '');
const side = signal.direction === 'long' ? 'BUY' : 'SELL';
const timestamp = Date.now();

// For LONG: buy with USDT (quoteOrderQty)
// For SHORT: sell base asset (requires existing position — spot only)
const sizeRounded = Math.floor(size * 100) / 100;
const queryString = `symbol=${symbol}&side=${side}&type=MARKET&quoteOrderQty=${sizeRounded}&timestamp=${timestamp}`;

const crypto = require('crypto');
const signature = crypto.createHmac('sha256', $env.BINANCE_API_SECRET)
  .update(queryString)
  .digest('hex');

return [{ json: { signal, portfolio, queryString, signature, symbol, side, timestamp, sizeRounded } }];

const orderResponse = $input.first().json;
const signal = $('Build Order').first().json.signal;

// Verify order was filled
if (orderResponse.status !== 'FILLED') {
  throw new Error(`Order not filled: ${JSON.stringify(orderResponse)}`);
}

const fills = orderResponse.fills || [];
const totalQty = fills.reduce((sum, f) => sum + parseFloat(f.qty), 0);
const totalCost = fills.reduce((sum, f) => sum + parseFloat(f.qty) * parseFloat(f.price), 0);
const avgPrice = totalQty > 0 ? totalCost / totalQty : parseFloat(signal.entry_price);

return [{
  json: {
    signal_id: signal.id,
    coin: signal.coin,
    direction: signal.direction,
    exchange_order_id: String(orderResponse.orderId),
    entry_price: avgPrice,
    position_size_usdt: parseFloat(signal.position_size_usdt),
    position_size_units: totalQty,
    initial_stop: parseFloat(signal.stop_loss),
    current_stop: parseFloat(signal.stop_loss),
    trailing_atr_mult: parseFloat(signal.trailing_atr_mult),
    trail_activation_pct: parseFloat(signal.trail_activation_pct)
  }
}];
